import { api } from '@/shared/api/client';
import { useQuery } from '@tanstack/react-query';

interface Ad {
  id: string;
  title: string;
  price: number;
  description: string;
}

export default function AdPage({ params }: { params: { id: string } }) {
  const { data, isLoading } = useQuery<Ad>({
    queryKey: ['ad', params.id],
    queryFn: async () => {
      const res = await api.get(`/ads/${params.id}`);
      return res.data as Ad;
    },
  });

  if (isLoading) return <div>Loading...</div>;
  if (!data) return <div>Not found</div>;

  return (
    <div>
      <h1>{data.title}</h1>
      <p>{data.price}</p>
      <p>{data.description}</p>
    </div>
  );
}
